const CATEGORY_BY_LABEL = new Map(
  CATEGORIES.map((category) => [normalizeCategoryLabel(category.label), category.id]),
);

const UNIT_PATTERN = /(?:x\s*)?(\d+(?:[,.]\d+)?\s*(?:kg|kilo|grs?|g|ml|cc|lts?|litros?|unid(?:ades)?|uds|saq\.?|sobres?|caps(?:ulas)?|comp(?:rimidos)?|hojas?|varillas?|bolitas?|sob))/i;
const PRICE_NUMBER_PATTERN = /(?<![a-zA-Z0-9])([0-9][0-9.,]*)(?![0-9.,])(?!(?:\s*)(?:gr|g|kg|ml|cc|lts?|litro|unid|uds|caps|comp|saq|sob))/i;

function normalizeCategoryLabel(value: string): string {
  return value.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, " ").trim().toLowerCase();
}

function normalizeProductName(value: string): string {
  return value.replace(/\s+/g, " ").trim();
}

function isInStock(name: string): boolean {
  return !OUT_OF_STOCK_PRODUCT_NAMES.has(normalizeProductName(name).toLowerCase());
}

function extractPrice(value: string | undefined): number | undefined {
  if (!value) return undefined;
  const text = value.trim();
  if (!text || /^(x|xx|-|g|unidad)$/i.test(text)) return undefined;
  const match = text.match(/\$\s*([0-9][0-9.,]*)/) ?? text.match(PRICE_NUMBER_PATTERN);
  if (!match) return undefined;
  const raw = match[1].replace(/[.,]+$/, "");
  const hasComma = raw.includes(",");
  const hasDot = raw.includes(".");
  let numeric = raw;
  if (hasComma && hasDot) {
    numeric = raw.lastIndexOf(",") > raw.lastIndexOf(".") && raw.split(",").at(-1)!.length <= 2 ? raw.replace(/\./g, "").replace(",", ".") : raw.replace(/,/g, "");
  } else if (hasComma) {
    const parts = raw.split(",");
    numeric = parts.at(-1)!.length <= 2 && parts.length === 2 ? raw.replace(",", ".") : parts.join("");
  } else if (hasDot) {
    const parts = raw.split(".");
    numeric = parts.at(-1)!.length === 3 ? parts.join("") : raw;
  }
  const parsed = Number.parseFloat(numeric);
  return Number.isFinite(parsed) && parsed > 0 ? Math.round(parsed) : undefined;
}

function applyMarkup(price: number | undefined): number | undefined {
  if (!price) return undefined;
  return Math.round((price * PRICE_MARKUP) / ROUND_TO) * ROUND_TO;
}

function inferUnitLabel(name: string, detail?: string): string {
  const source = `${name} ${detail ?? ""}`;
  const match = source.match(UNIT_PATTERN);
  return match?.[1].replace(/\s+/g, " ").trim() ?? "unidad";
}

function hasWeightHint(name: string, details: string[]): boolean {
  const source = `${name} ${details.join(" ")}`.toLowerCase();
  return /\bkg\b|\bkilo\b|1\/?2\s*k|500\s*g|500gr|x500/.test(source);
}

function makeId(category: CategoryId, index: number): string {
  return `${category}-${String(index).padStart(3, "0")}`;
}

function parseRawProducts(): RawProduct[] {
  const products: RawProduct[] = [];
  const categoryCounts = new Map<CategoryId, number>();
  let currentCategory: CategoryId | null = null;
  let currentMode: CategoryMode = "unit";

  for (const line of RAW_CATALOG_TEXT.split("\n")) {
    const columns = line.split("\t").map((column) => column.trim());
    const name = normalizeProductName(columns[0] ?? "");
    if (!name) continue;

    const categoryId = CATEGORY_BY_LABEL.get(normalizeCategoryLabel(name));
    if (categoryId) {
      currentCategory = categoryId;
      currentMode = CATEGORY_MODES[categoryId] ?? "unit";
      continue;
    }
    if (!currentCategory) continue;

    const priceA = extractPrice(columns[1]);
    const priceB = extractPrice(columns[2]);
    if (!priceA && !priceB) continue;

    const nextIndex = (categoryCounts.get(currentCategory) ?? 0) + 1;
    categoryCounts.set(currentCategory, nextIndex);
    const details = columns.slice(1);
    const useWeightPricing = currentMode === "weight" || (currentMode === "mixed" && (Boolean(priceB) || hasWeightHint(name, details)));

    if (useWeightPricing) {
      products.push({ id: makeId(currentCategory, nextIndex), name, category: currentCategory, inStock: isInStock(name), priceKg: applyMarkup(priceA), price500gr: applyMarkup(priceB) });
      continue;
    }
    products.push({ id: makeId(currentCategory, nextIndex), name, category: currentCategory, inStock: isInStock(name), fixedPrice: applyMarkup(priceA ?? priceB), unitLabel: inferUnitLabel(name, details.join(" ")) });
  }
  return dedupeProducts(products);
}

function dedupeProducts(products: RawProduct[]): RawProduct[] {
  const seen = new Set<string>();
  return products.filter((product) => {
    const key = [product.category, product.name.toLowerCase(), product.priceKg ?? "", product.price500gr ?? "", product.fixedPrice ?? "", product.unitLabel ?? ""].join("|");
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

const RAW_PRODUCTS: RawProduct[] = parseRawProducts();

function normalizeProduct(raw: RawProduct): Product {
  return { id: raw.id, name: raw.name, category: raw.category, description: raw.description, inStock: raw.inStock, price500gr: raw.price500gr, priceKg: raw.priceKg, unitLabel: raw.unitLabel, fixedPrice: raw.fixedPrice };
}

export function getProductVariant(product: Product): ProductVariant | null {
  if (product.price500gr) return { unit: "500gr", unitLabel: "500 gr", unitPrice: product.price500gr };
  if (product.priceKg) return { unit: "kg", unitLabel: "1 kg", unitPrice: product.priceKg };
  if (product.fixedPrice && product.unitLabel) return { unit: "unidad", unitLabel: product.unitLabel, unitPrice: product.fixedPrice };
  return null;
}

export const PRODUCTS: Product[] = RAW_PRODUCTS.map(normalizeProduct).filter((product) => getProductVariant(product) !== null);

export function getProductsByCategory(category: CategoryId): Product[] {
  return PRODUCTS.filter((product) => product.category === category);
}

export function getCategoryProductCount(category: CategoryId): number {
  return getProductsByCategory(category).length;
}
